func isUnicode13Repertoire(value string) bool {
	for _, scalar := range value {
		index := sort.Search(len(unicode13Ranges), func(index int) bool {
			return unicode13Ranges[index].last >= scalar
		})
		if index == len(unicode13Ranges) || unicode13Ranges[index].first > scalar {
			return false
		}
	}
	return true
}
